ee:message.ee:set-payload:
%dw 2.0
output application/java

var bal = (vars.customer.BALANCE default 0) as Number

var loan =
    if (bal >= 500000)
        {
            loanType: "HOME LOAN",
            offerAmount: 5000000,
            interestRate: 8.25,
            tenure: 240
        }
    else if (bal >= 200000)
        {
            loanType: "CAR LOAN",
            offerAmount: 1000000,
            interestRate: 9.25,
            tenure: 84
        }
    else
        {
            loanType: "PERSONAL LOAN",
            offerAmount: 200000,
            interestRate: 11.50,
            tenure: 60
        }

---
{
    offerId: "OFF-" ++ (now() as String {format:"yyyyMMddHHmmss"}),
    accountNumber: vars.customer.ACCOUNTNUMBER,
    customerId: vars.customer.CUSTOMER_ID,
    customerName: vars.customer.FULLNAME,
    email: vars.customer.EMAIL,
    mobile: vars.customer.MOBILENUMBER,
    balance: bal
} ++ loan

set-variable.value:
#[%dw 2.0
output application/java

var customerName = (vars.customer.FULLNAME default "Customer") as String
var loanType = (vars.loanOffer.loanType default "-") as String
var offerAmount = (vars.loanOffer.offerAmount default 0) as String
var interestRate = (vars.loanOffer.interestRate default 0) as String
var tenure = (vars.loanOffer.tenure default 0) as String
var accountNumber = (vars.loanOffer.accountNumber default "") as String

var maskedAccount =
    if (sizeOf(accountNumber) >= 4)
        "XXXXXX" ++ accountNumber[(sizeOf(accountNumber)-4) to (sizeOf(accountNumber)-1)]
    else
        "XXXXXX0000"

---
"<!DOCTYPE html>
<html>
<head>
<meta charset='UTF-8'>
<meta name='viewport' content='width=device-width, initial-scale=1.0'>

<style>

body{
margin:0;
padding:30px;
background:#eef3f8;
font-family:Segoe UI,Arial,sans-serif;
}

.wrapper{
max-width:700px;
margin:auto;
background:#ffffff;
border-radius:18px;
overflow:hidden;
box-shadow:0 12px 35px rgba(0,0,0,.12);
}

.header{
background:linear-gradient(135deg,#003366,#0059b3,#0099ff);
padding:40px;
text-align:center;
color:white;
}

.header h1{
margin:0;
font-size:34px;
}

.header p{
margin-top:10px;
font-size:16px;
opacity:.95;
}

.content{
padding:40px;
}

.greeting{
font-size:20px;
font-weight:bold;
color:#003366;
}

.message{
font-size:16px;
line-height:28px;
color:#555;
margin-top:20px;
}

.offer{
margin-top:30px;
border-radius:12px;
background:#f8fbff;
border:1px solid #d7e8ff;
padding:25px;
}

.offer table{
width:100%;
border-collapse:collapse;
}

.offer td{
padding:15px;
font-size:16px;
border-bottom:1px solid #dde7f3;
}

.offer td:first-child{
font-weight:bold;
color:#003366;
width:45%;
}

.amount{
font-size:30px;
font-weight:bold;
color:#008000;
}

.button{
margin-top:35px;
text-align:center;
}

.button a{
background:#0066ff;
color:white;
padding:16px 40px;
border-radius:40px;
text-decoration:none;
font-size:18px;
font-weight:bold;
display:inline-block;
}

.note{
margin-top:30px;
padding:18px;
background:#fff9e8;
border-left:5px solid #ffc107;
border-radius:8px;
font-size:15px;
line-height:24px;
color:#555;
}

.footer{
margin-top:35px;
padding:25px;
background:#003366;
color:white;
text-align:center;
font-size:14px;
}

.footer h3{
margin:0;
font-size:22px;
}

.footer p{
margin:10px 0;
}

</style>

</head>

<body>

<div class='wrapper'>

<div class='header'>

<h1>🏦 Dream Bank</h1>

<p>Exclusive Pre-Approved Loan Offer</p>

</div>

<div class='content'>

<div class='greeting'>

Dear " ++ customerName ++ ",

</div>

<div class='message'>

Congratulations!

Based on your excellent banking relationship and account activity,
you have been selected for a <b>Pre-Approved Loan Offer</b>.

No additional documentation is required for initial eligibility.

</div>

<div class='offer'>

<table>

<tr>
<td>Loan Type</td>
<td>" ++ loanType ++ "</td>
</tr>

<tr>
<td>Eligible Amount</td>
<td class='amount'>₹ " ++ offerAmount ++ "</td>
</tr>

<tr>
<td>Interest Rate</td>
<td>" ++ interestRate ++ "% p.a.</td>
</tr>

<tr>
<td>Repayment Tenure</td>
<td>" ++ tenure ++ " Months</td>
</tr>

<tr>
    <td>Account Number</td>
    <td>" ++ maskedAccount ++ "</td>
</tr>

</table>

</div>

<div class='button'>

<a href='https://dreambank.com'>Accept Offer</a>

</div>

<div class='note'>

<b>Important</b><br>

• Offer is valid for 30 days.<br>
• Interest rate may vary after expiry.<br>
• Terms & Conditions apply.<br>
• This offer is generated automatically based on your banking profile.

</div>

</div>

<div class='footer'>

<h3>Dream Bank</h3>

<p>Your Trusted Banking Partner</p>

<p>
Customer Care : 9494207062<br>
support.realbank@gmail.com
</p>

<p>

© 2026 Dream Bank. All Rights Reserved.

</p>

</div>

</div>

</body>

</html>"]
